-- Seed data for the romantic birthday app.
-- Safe to re-run: uses ON CONFLICT upserts for tables with unique keys.

-- =========================
-- Journey (Daily Surprises)
-- =========================
ON CONFLICT (day_number)
DO UPDATE SET
  type = EXCLUDED.type,
  title = EXCLUDED.title,
  content = EXCLUDED.content,
  media_url = EXCLUDED.media_url;

-- ==================
-- For You (Reasons)
-- ==================
ON CONFLICT (unlock_day)
DO UPDATE SET
  reason_text = EXCLUDED.reason_text;

-- =================
-- Compliments (50)
-- =================
ON CONFLICT (compliment_text)
DO NOTHING;

-- =========
-- Coupons
-- =========
-- Note: redemption state lives in coupon_redemptions.
ON CONFLICT (title)
DO UPDATE SET
  description = EXCLUDED.description,
  icon = EXCLUDED.icon,
  color = EXCLUDED.color;

