INSERT INTO daily_surprises (day_number, type, title, content, media_url)
VALUES
  (1, 'letter', 'A tiny beginning', '💌✨ Hey love. If you ever doubt yourself today, remember this: you have a way of making ordinary moments feel like home. 🏡💗 I’m proud of you for showing up, for trying, for being you — even when you feel tired. 🌙🫶 Take a slow breath for me 😮‍💨 and keep going gently.', NULL),
  (2, 'letter', 'I notice you', '👀💞 I notice you — the way you care softly, the way you try without needing applause, the way you keep your heart gentle. 🌸🥹 That kind of love is rare. And you’re rare. ✨🫶 If nobody told you today: you’re doing amazing, and I’m grateful I get to love you. 💗', NULL),
  (3, 'letter', 'For your smile', '☀️😊 Your smile doesn’t just brighten a room — it changes the weather inside me. 🌤️💓 When you smile, my mind gets quiet and my heart gets loud. 🥹💗 I hope you smile today, even if it’s small. And if you don’t, that’s okay — I’ll hold the day gently for you. 🫶🌙', NULL),
  (4, 'letter', 'The calm you bring', '🌊🫶 When life gets loud, you are the quiet I want. The safe I choose. The peace my heart recognizes. 🕊️💗 I love how you make things feel softer just by being near. ✨ If today is chaos, come back to me in tiny ways — a message, a thought, a breath. 📩😮‍💨', NULL),
  (5, 'letter', 'A promise', '💍💗 I promise to keep learning you — your dreams, your fears, your favorite little joys. 🌸🧠 I promise to love you better as I learn, not louder… just deeper. 🌙✨ And I promise to never make you feel like your heart is “too much.” It’s beautiful. It’s home. 🏡🫶', NULL),
  (6, 'letter', 'Your softness is strength', '🛡️🌸 Your gentleness isn’t weakness — it’s strength with grace. ✨💗 You’re soft, but you’re not fragile. You care, but you don’t break. 🫶 If the world ever tries to harden you, remember: your softness is part of your magic. 🪄🌙', NULL),
  (7, 'letter', 'One thing I adore', '🥰🎀 I adore how you can be both serious and silly. How you can be deep and playful. 🌊✨ You’re poetry and chaos in the sweetest balance, and it makes me smile every time. 😊💗 Never shrink the parts of you that feel alive. 🫶', NULL),
  (8, 'letter', 'A warm thought', '🧸💞 If I could, I’d wrap you in a blanket made from every good memory we’ve made and every good thing still coming. 🧵✨ I’d keep you warm from doubt, stress, and sadness. 🌙🫶 Until then, keep this: you’re loved, you’re safe, you’re mine. 💗', NULL),
  (9, 'letter', 'You are my favorite habit', '💭💗 Thinking about you is my favorite habit. Loving you is my favorite decision. 🫶✨ I love the tiny ways you live in my day — in songs, in random moments, in the quiet. 🎶🌙 If you ever wonder if you matter to me… you do. Constantly. 💞', NULL),
  (10, 'letter', 'The way you try', '🌟🫶 Even on hard days, you keep trying. That’s one of the most beautiful things about you. 🥹💗 I see it. I admire it. I’m proud of it. 🏆✨ Please don’t measure yourself by your tired moments — measure yourself by your heart. It’s huge. 💞', NULL),
  (11, 'letter', 'I’d choose you', '🫶💍 In a room full of chances, I’d still choose you. Again. And again. ✨💗 Not because it’s easy — because it’s real. Because your heart feels like something I want to keep safe. 🧸🌙 I’m grateful for you. Always.', NULL),
  (12, 'letter', 'Your laugh', '😂💗 Your laugh is one of my favorite sounds — it feels like sunshine with a heartbeat. ☀️💓 I hope life gives you reasons to laugh today, and if it doesn’t… I’ll try to be one. 🫶✨ You deserve joy that finds you easily. 🌈', NULL),
  (13, 'letter', 'A small reminder', '🚰💞 Drink water. 😮‍💨 Take a breath. 🧸 Be gentle with yourself. 🌙✨ You don’t have to do everything perfectly to be lovable — you’re already loved. 🫶💗 I’m cheering for you quietly in the background like your personal lucky charm. 🍀', NULL),
  (14, 'letter', 'You make things softer', '🫧💗 You have this gift: you make people feel less alone. You made me feel less alone. 🌙🫶 That matters more than you know. ✨ Today, if you feel overwhelmed, remember you’re not carrying life by yourself — you have me. Always. 🧸', NULL),
  (15, 'letter', 'My favorite timeline', '⏳💞 My favorite timeline is the one where I get to love you openly, patiently, and on purpose. 💗✨ Where your smile becomes my routine and your peace becomes our habit. 🏡🌙 I want to build a life that feels soft to live in — with you. 🫶', NULL),
  (16, 'letter', 'A love note with courage', '🫶🔥 If you feel scared today, take my hand anyway. We can be brave together. 🌙✨ You don’t have to be fearless — just willing. And you already are. 💗 I believe in you more than you know. 🥹', NULL),
  (17, 'letter', 'The future sounds like you', '🔮💗 When I think of the future, it sounds like your name said gently. 🌙✨ It feels like calm mornings, soft nights, and a love that keeps choosing. 🏡🫶 If the future ever feels uncertain, remember: you’re my favorite certainty. 💞', NULL),
  (18, 'letter', 'Your heart is a place', '🏡💗 Your heart is a place I want to treat with care — not just today, always. 🫶✨ I want to be the person who brings you comfort, not confusion. 🌙🥹 You deserve love that feels safe, steady, and kind. 💞', NULL),
  (19, 'letter', 'You are not “too much”', '🛑💗 You are not “too much.” Not too emotional. Not too sensitive. Not too intense. 🌙✨ You are a blessing — and anyone who loves you properly will understand that your heart is a gift. 🫶🥹 I love you exactly as you are. 💞', NULL),
  (20, 'letter', 'Thank you', '🙏💗 Thank you for existing exactly as you are. Thank you for letting me love you. Thank you for being my favorite. 🫶✨ If I could put my gratitude in your hands, it would look like flowers, warm tea, and a long hug. 🌸🫖🫂', NULL),
  (21, 'letter', 'A gentle dare', '💗✨ Today, let yourself receive love without questioning it. 🫶🌙 Start with mine. 💌 If your mind tries to argue, just breathe and say: “I deserve softness.” 😮‍💨🧸 Because you do. Always.', NULL),
  (22, 'letter', 'Your magic', '🪄💗 Your magic is in the details: the way you listen, the way you remember, the way you show up. ✨🫶 It’s not loud — it’s real. 🌙🥹 I’m still amazed by you, even in the simplest moments. 💞', NULL),
  (23, 'letter', 'Even on tired days', '😴💗 Even on tired days, you are worthy of tenderness. 🧸✨ You don’t have to “earn” rest or affection. 🌙🫶 I hope you treat yourself like someone you love today — gently, patiently, kindly. 💞', NULL),
  (24, 'letter', 'My favorite place', '🫶🏡 My favorite place is anywhere your hand fits in mine. ✨💗 It’s not about where we are — it’s about who I’m with. 🌙😊 I want more moments that feel like that: simple, close, and safe. 🧸', NULL),
  (25, 'letter', 'A soft confession', '🥹💗 Sometimes I catch myself smiling for no reason… then I realize I was thinking about you. 😊✨ You live in my thoughts like a song I don’t get tired of. 🎶🌙 If you ever feel far, remember: you’re still with me. Always. 🫶', NULL),
  (26, 'letter', 'You deserve ease', '🍃💗 I hope life meets you gently today. And if it doesn’t, I’ll meet you gently anyway. 🫶🌙 You deserve ease, softness, and love that doesn’t feel heavy. ✨🧸 I want to be a safe place, not another storm.', NULL),
  (27, 'letter', 'You are a masterpiece', '🎨💗 You are a masterpiece — not because you’re perfect, but because you’re real. ✨🫶 Your growth is beautiful. Your effort is beautiful. 🌙🥹 Don’t rush yourself. I love every version of you. 💞', NULL),
  (28, 'letter', 'I’m on your side', '🫶💗 In every version of every story, I’m on your side. Always. ✨ If the world feels unfair, if your thoughts feel loud, if people misunderstand you — I’m still here. 🌙🧸 You and me. Same team. 💞', NULL),
  (29, 'letter', 'A little sparkle', '✨💗 You bring sparkle to ordinary days. Not the fake kind — the real kind that comes from warmth and presence. 🫶😊 If today feels dull, remember you’re still bright. 🌙⭐ You don’t have to perform to shine.', NULL),
  (30, 'letter', 'How lucky I feel', '🍀💗 I feel lucky — quietly, deeply, constantly — that I get to love you. ✨🫶 I don’t take your heart for granted. 🌙🥹 If I could, I’d remind you every day: you are precious to me. 💞', NULL),
  (31, 'letter', 'Soft pride', '🏆💗 I’m proud of the person you are and the person you’re becoming. 🌸✨ I’m proud of your effort, your resilience, your softness. 🫶🌙 And I hope you’re proud too — because you’re doing better than you think. 🥹', NULL),
  (32, 'letter', 'I love your mind', '🧠💗 I love the way you think — the way you connect things, the way you notice what others miss. ✨🫶 Your mind is beautiful to me. 🌙📚 I want to listen to your thoughts forever, even the messy ones. 💞', NULL),
  (33, 'letter', 'Small comfort', '😮‍💨💗 If today feels too big, take it one breath at a time. 🫶🌙 You don’t have to solve everything at once. 🧸✨ Just take the next gentle step. I’m with you in the small moments — that’s where love lives too. 💞', NULL),
  (34, 'letter', 'Your light is real', '✨💗 You don’t have to be “on” to be loved. Not productive, not perfect, not smiling. 🌙🫶 You’re loved in your quiet, your messy, your tired too. 🧸🥹 Let yourself rest without guilt today. 💞', NULL),
  (35, 'letter', 'A gentle celebration', '🎉💗 I hope you celebrate yourself today — even if it’s just a tiny thing. 🌸✨ A small win, a soft moment, a deep breath. 🫶🌙 You deserve to feel proud of you. I’m proud of you. 🥹🏆', NULL),
  (36, 'letter', 'You’re my favorite thought', '💭💗 Sometimes I pause and just think of you. It’s like my heart stretches and relaxes at the same time. 🫶🌙 You make me feel calm and excited in one breath. 😮‍💨✨ I love you. Simply. Deeply. Always. 💞', NULL),
  (37, 'letter', 'My safe place', '🏡💗 You feel like a safe place I can return to. 🌙🫶 Thank you for being gentle with me, for letting love feel soft. ✨🧸 I want to be that safe place for you too — a home for your heart. 💞', NULL),
  (38, 'letter', 'I trust you', '🤍💗 I trust your heart. I trust your intentions. I trust the love you carry. 🫶✨ And I trust that you’ll keep growing into the life you deserve. 🌙🌱 If you ever forget your own strength, borrow my belief. 💞', NULL),
  (39, 'letter', 'Your tenderness', '🫧💗 Your tenderness is a gift. The world needs more of it. I need more of it. 🌙🫶 I love how you care in quiet ways, how you hold people gently. ✨🧸 Please don’t let life harden you. Your softness is your beauty. 💞', NULL),
  (40, 'letter', 'You deserve good mornings', '☀️💗 You deserve mornings that feel calm — warm light, soft thoughts, good news. 🫶✨ And even if your morning isn’t perfect, you still deserve kindness from yourself. 🌙🧸 I’m sending you love like a little sunrise in your pocket. 🌅💞', NULL),
  (41, 'letter', 'Your effort is love', '🫶💗 The way you try, the way you show up, the way you care — those are love languages too. ✨🌙 You don’t have to do grand gestures to be incredible. 🧸🥹 Your consistency is beautiful. Your heart is beautiful. 💞', NULL),
  (42, 'letter', 'A quiet promise', '🤍💗 I’ll keep choosing you in the small moments. In the ordinary. In the calm. 🫶✨ That’s where forever lives — not in fireworks, but in steady love. 🌙🏡 I want to be steady for you. Always. 💞', NULL),
  (43, 'letter', 'You’re enough', '🪞💗 Not “almost.” Not “when you fix this.” Not “when you’re better.” You, right now, are enough. 🫶✨ If your mind tries to argue, I’ll say it louder: you’re enough. 🌙🥹 You always have been. 💞', NULL),
  (44, 'letter', 'My favorite warmth', '🔥💗 If I could bottle one feeling, it would be the warmth I feel when you’re near. 🫶✨ It’s comfort, excitement, peace — all mixed together. 🌙😊 I hope you feel loved today in a way that makes your shoulders relax. 😮‍💨🧸', NULL),
  (45, 'letter', 'I love your honesty', '🤍💗 I love how real you are — how you don’t fake softness or strength. 🫶✨ You show up honestly, even when it’s hard. 🌙🥹 That’s rare. That’s beautiful. And I love you for it — every honest piece. 💞', NULL),
  (46, 'letter', 'You are loved loudly', '❤️‍🔥💗 If you ever can’t hear it from the world, hear it from me: you are loved. Deeply. Softly. Completely. 🫶🌙 You don’t have to prove you deserve it. ✨🧸 I love you because you’re you. That’s enough. 💞', NULL),
  (47, 'letter', 'You make time sweeter', '⏳💗 You make time feel sweeter. Slower. Like it’s okay to breathe. 😮‍💨✨ I love being in the same moment as you, even when nothing special is happening. 🫶🌙 Because with you, it always feels special. 💞', NULL),
  (48, 'letter', 'I’m grateful', '🙏💗 I’m grateful for you — your heart, your presence, your patience, your whole beautiful self. 🫶✨ Thank you for existing in my life. 🌙🥹 I don’t say it enough, but I feel it all the time: I’m lucky to love you. 💞', NULL),
  (49, 'letter', 'A little kiss in words', '💋💗 Pretend this is a kiss on your forehead — the kind that says: I’ve got you. 🫶🌙 The kind that makes you feel safe. 🧸✨ If today is tough, let this be your reminder: you’re not alone. I’m here. 💞', NULL),
  (50, 'letter', 'Still you', '💍💗 Even after everything, it’s still you. It will always be you for me. 🫶✨ I don’t love you for the perfect days only — I love you in the real days, the messy days, the quiet days. 🌙🧸 I love you. Always. 💞', NULL)
